import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { isAdmin, isEmployee, getLoggedInUser } from "../auth";

function EmployeeDetails() {

  const navigate = useNavigate();

  const user = getLoggedInUser();
  const role = user?.role?.toUpperCase();

  const base =
    role === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* ================= STATE ================= */
  const [employees, setEmployees] = useState([]);
  const [searchEmpId, setSearchEmpId] = useState("");
  const [loading, setLoading] = useState(true);

  /* ================= LOAD EMPLOYEES ================= */
  useEffect(() => {

    const loadEmployees = async () => {

      try {

        const token = localStorage.getItem("token");

        const response = await fetch(
          "http://localhost:8080/api/employees",
          {
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`
            }
          }
        );

        // ⭐ Handle auth failures cleanly
        if (response.status === 401 || response.status === 403) {
          console.error("Unauthorized — check role/token");
          setEmployees([]);
          return;
        }

        const data = await response.json();

        // ⭐ Defensive check
        if (Array.isArray(data)) {
          setEmployees(data);
        } else {
          console.warn("Unexpected API response:", data);
          setEmployees([]);
        }

      } catch (err) {
        console.error("Employee load failed:", err);
        setEmployees([]);
      } finally {
        setLoading(false);
      }
    };

    loadEmployees();

  }, []);

  /* ================= FILTER ================= */
  const filteredEmployees = isAdmin()
    ? employees.filter(emp =>
        (emp.empId || "")
          .toLowerCase()
          .includes(searchEmpId.toLowerCase())
      )
    : employees;

  /* ================= NAME HELPER ================= */
  const getEmployeeName = (emp) =>
    `${emp?.firstName || ""} ${emp?.lastName || ""}`.trim();

  /* ================= UI ================= */
  return (
    <div className="employee-page">

      <h2 className="employee-title">Manage Employees</h2>

      <div className="employee-actions">

        {isAdmin() && (
          <input
            type="text"
            placeholder="Search By Employee ID"
            className="search-box"
            value={searchEmpId}
            onChange={(e) => setSearchEmpId(e.target.value)}
          />
        )}

        {isAdmin() && (
          <button
            className="add-btn"
            onClick={() =>
              navigate(`${base}/employee-details/add`)
            }
          >
            Add New Employee
          </button>
        )}
      </div>

      {/* ================= TABLE ================= */}
      <table className="employee-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>
            {(isAdmin() || isEmployee()) && <th>Action</th>}
          </tr>
        </thead>

        <tbody>

          {/* ⭐ Loading State */}
          {loading && (
            <tr>
              <td colSpan="5">Loading employees...</td>
            </tr>
          )}

          {/* ⭐ Data */}
          {!loading && filteredEmployees.length > 0 &&
            filteredEmployees.map((emp, index) => (
              <tr key={emp.id}>
                <td>{index + 1}</td>
                <td>{getEmployeeName(emp)}</td>
                <td>{emp?.dob || "--"}</td>
                <td>{emp?.department || "--"}</td>

                {isAdmin() && (
                  <td className="actions">
                    <button
                      className="view"
                      onClick={() =>
                        navigate(`${base}/employee-details/view/${emp.id}`)
                      }
                    >
                      View
                    </button>

                    <button
                      className="edit"
                      onClick={() =>
                        navigate(`${base}/employee-details/edit/${emp.id}`)
                      }
                    >
                      Edit
                    </button>

                    <button
                      className="salary"
                      onClick={() =>
                        navigate(`${base}/employee-details/salary/add/${emp.id}`)
                      }
                    >
                      Salary
                    </button>

                    <button className="delete">
                      Delete
                    </button>
                  </td>
                )}

                {isEmployee() && (
                  <td>
                    <button
                      className="salary"
                      onClick={() =>
                        navigate(`${base}/employee-details/leave/apply/${emp.id}`)
                      }
                    >
                      Apply Leave
                    </button>
                  </td>
                )}

              </tr>
            ))
          }

          {/* ⭐ Empty */}
          {!loading && filteredEmployees.length === 0 && (
            <tr>
              <td colSpan="5" className="no-data">
                No Employees Found
              </td>
            </tr>
          )}

        </tbody>
      </table>

    </div>
  );
}

export default EmployeeDetails;
